unitsize(0.5cm);
pair A,B,C,D,H;
A=(0,0);
H=(1,0);
B=(2,0);
D=(5,0);
C=(1,6);
draw(A--C--D--cycle,linewidth(0.7));
draw(H--C--B--cycle,linewidth(0.7));
label("1",(0.5,0),N);
label("1",(1.5,0),N);
label("7",(0.5,3),NW);
label("7",(1.5,3),NE);
label("8",(3.5,3),NE);
label("$A$",A,S);
label("$B$",B,S);
label("$D$",D,S);
label("$H$",H,S);
label("$C$",C,N);
[/asy]

